"""
MKT Christ Commentary — Hebrews chapters 12–13
Run: python3 scripts/zc-christ-hebrews-12-13.py

Source data used:
- data/interlinear/hebrews.json
- data/translation/draft/mediating/hebrews.json
- data/commentary/mkt-christ/hebrews.json (existing entries for chs 1–11)

Key decisions in this range:
- 12:2 pioneer and perfecter: "A direct revelation:" — Jesus as the one who ran and won the race before us
- 12:5-9 discipline theology: "A revelation of God:" — fatherly discipline patterned on the Son's own suffering
- 12:10 share in his holiness: "A direct revelation:" — goal of discipline as divine-character participation
- 12:16-17 Esau: "A shadow:" — the negative type of despising covenant inheritance
- 12:18-21 Sinai: "A revelation of God:" — the old covenant's terror reveals what the new removes
- 12:22-24 heavenly assembly: "A direct revelation:" — present eschatological community
- 12:24 better blood: "A direct revelation:" — Christ's blood vs. Abel's
- 12:25-29 unshakeable kingdom: "A fulfillment:" / "A revelation of God:"
- 13:10-11 altar / sin-offering: "A direct revelation:" / "A shadow:"
- 13:15-16 sacrifice of praise: "A direct revelation:" — the new covenant's priestly worship
- 13:20-21 God of peace/great shepherd: "A direct revelation:" — the resurrection benediction
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

HEBREWS = {
  "12": {
    "1": '<p>A direct revelation: surrounded by such a great cloud of witnesses, let us run with endurance the race that is set before us. The community\'s race is not run in isolation but within the communion of all the faith-witnesses who have gone before — Abel, Noah, Abraham, Moses, and all the rest. Their completed testimony surrounds and encourages the current runners. The race metaphor identifies the Christian life as a contest with a defined goal, a defined course (set before us — already established by Christ\'s own completion of it), and a defined means of success (endurance: bearing the weight of suffering to the finish rather than quitting).</p>',
    "2": '<p>A direct revelation: looking to Jesus, the pioneer and perfecter of our faith, who for the joy set before him endured the cross, despising the shame, and is seated at the right hand of the throne of God. The Christian race is not run by following an abstract ideal but by fixing the gaze on a person who has already run it and completed it. Jesus is pioneer (he went first, opening the path) and perfecter (he brought faith to its completion and goal) — both the trailblazer and the finisher. His joy-despite-cross, honor-despite-shame, and current session are the revelation of what the race looks like: suffering through to glory.</p>',
    "3": '<p>A direct revelation: consider him who endured such hostility from sinners against himself, so that you will not grow weary and lose heart. The antidote to weariness is contemplation of Christ — considering the opposition he bore enables the community to calibrate their own suffering accurately. The comparison is not "your suffering is nothing" but "what he endured was greater, and he did not quit." The person of Christ is the specific, inexhaustible remedy for spiritual fatigue: the more clearly they see his endurance, the more sustainable their own becomes.</p>',
    "4": '<p>A direct revelation: in your struggle against sin, you have not yet resisted to the point of shedding your blood. The outer limit of the community\'s required endurance is Christ\'s blood-shedding — the maximum they have not yet been called to match. This calibrates their sense of suffering: serious, but not yet at its outer boundary. Christ\'s blood-shedding is both the comparison point (he was pressed further than they have been) and the ground of their endurance (his blood-shedding was for them, so they are covered and sustained).</p>',
    "5": '<p>A revelation of God: the Proverbs 3:11-12 citation applied to the community\'s experience of suffering: "My son, do not make light of the Lord\'s discipline." The same God who gave the Son into suffering now gives the community into their lesser suffering. The fatherly address ("my son") reveals the relational character of the discipline: not penal retribution but parental formation. The community\'s suffering is not evidence of God\'s absence but of his active, engaged, fatherly attention to their formation in Christ.</p>',
    "6": '<p>A revelation of God: the Lord disciplines the one he loves and chastens every son he accepts. The equation of discipline with love and acceptance reveals the character of the God who sent the Son into suffering. The cross is the supreme instance of this principle: the beloved Son was not spared but sent into the ultimate discipline of suffering-unto-death. The Father\'s love did not prevent the Son\'s suffering but worked through it toward resurrection-glory. The community\'s suffering is patterned on the Son\'s, and both are expressions of the Father\'s loving engagement.</p>',
    "7": '<p>A direct revelation: endure hardship as discipline; God is treating you as his children. Those who are in Christ are children of God — a sonship secured by Christ (2:10-11: "he is not ashamed to call them brothers") — and the Father treats them as children, which includes the fatherly discipline that forms character. Christ himself received this treatment (5:8: he learned obedience through what he suffered), and the community follows their older brother in the same path of suffering-shaped formation toward the goal of sharing his holiness.</p>',
    "8": '<p>A revelation of God: if you are not disciplined, then you are illegitimate and not true children. The absence of discipline would be evidence of not belonging — the illegitimate children are those the Father does not take responsibility for forming. The community\'s suffering, viewed through this logic, is a sign of genuine sonship, not divine indifference. Christ\'s sonship was supremely evidenced by the Father\'s commitment to send him through the fullness of human suffering; the community\'s sonship is evidenced by the same disciplinary love applied in lesser measure.</p>',
    "9": '<p>A revelation of God: we respected our human fathers who disciplined us — how much more should we submit to the Father of spirits and live? The a-fortiori argument reveals the character of God as the Father of spirits — the one who gives life and who, in disciplining, is working toward life rather than away from it. In Christ, the logic is enacted definitively: perfect submission to the Father through the extreme suffering of the cross produced resurrection-life. The community\'s submission to the disciplining Father follows the Son\'s pattern and leads toward the same goal.</p>',
    "10": '<p>A direct revelation: God disciplines us for our good, that we may share his holiness. The goal of the entire discipline-theology is participation in the divine character — specifically in holiness. This is not merely ethical conformity but ontological transformation: the disciplined community is being made to share what God is. The incarnate Son who lived the path of suffering-to-glory is the pattern; the community is being formed into his image by the same Father who formed the Son through the disciplines of obedience (5:8) and who raised him to the glory of the divine holiness.</p>',
    "11": '<p>A direct revelation: no discipline seems pleasant at the time, but painful. Later on, however, it produces a harvest of righteousness and peace for those who have been trained by it. The temporal structure of discipline — painful present, harvest-producing future — is the shape of Christ\'s own path: "for the joy set before him he endured the cross" (v. 2). The harvest of righteousness is not the community\'s earning of their standing but the fruit of being formed into the righteousness-pattern of the one who perfected faith before them. The peace of the harvest anticipates the eschatological shalom of the kingdom.</p>',
    "12": '<p>A theme: strengthen your feeble arms and weak knees. The quotation from Isaiah 35:3 — the restoration-of-the-weak oracle of the age of salvation — is applied to the community\'s present condition. The arms and knees weakened by persecution are to be strengthened by the certainty of the coming restoration that Isaiah envisioned. Christ is the one in whom that restoration has begun: he healed the lame, strengthened the weak, and raised the dead. The community participates in the same healing trajectory while it awaits its completion.</p>',
    "13": '<p>A theme: make level paths for your feet, so that the lame may not be disabled but rather healed. The community\'s path-leveling is both personal discipline (choosing the straight way) and communal responsibility (helping the weak rather than causing them to fall). The healing of the lame echoes Isaiah 35:6 — the messianic sign that Christ enacted in his earthly ministry (Matt 11:5; Luke 7:22). What Christ began in healing the physically lame, the community is called to continue by enabling the spiritually vulnerable to walk straight rather than stumble into apostasy.</p>',
    "14": '<p>A revelation of God: make every effort to live in peace with everyone and to be holy; without holiness no one will see the Lord. The holiness required to see the Lord is not achieved by human effort alone but has been given through Christ (13:12: the people sanctified through his own blood). The community pursues holiness as those who have already received it in principle through Christ\'s one offering (10:14). "See the Lord" is the eschatological promise — the beatific vision that Christ\'s atonement has made possible and that his return will make actual.</p>',
    "15": '<p>A revelation of God: see that no one fails to obtain the grace of God, and that no bitter root grows up to cause trouble and defile many. The grace of God is the entire provision of the new covenant — the atonement, the opened sanctuary, the Spirit, the access to the Father — of which any member of the community could "fall short" by turning back from Christ. The bitter root from Deuteronomy 29:18 is the apostasy that defiles many. The communal warning reveals that individual defection from Christ has corporate consequences: one person\'s turning away infects the fellowship and testimony of the whole.</p>',
    "16": '<p>A shadow: see that no one is sexually immoral or godless like Esau, who for a single meal sold his inheritance rights as the firstborn. Esau is the negative type of the one who despises a covenant blessing for immediate gratification. His birthright ran through the covenant line that pointed ultimately toward Christ — the promised seed, the blessing of Abraham. The warning to the community is analogous: the spiritual inheritance — the heavenly country, the unshakeable kingdom, the eternal covenant — is what is at stake when temporal pressures make the return to the old order seem attractive.</p>',
    "17": '<p>A revelation of God: when he afterward wanted to inherit the blessing, he was rejected, for he found no chance to repent, though he sought it with tears. Esau\'s inability to recover what he had despised is the warning about irreversibility — the finality of certain choices. The parallel to the apostasy warnings of 6:4-6 and 10:26 is clear: some deliberate rejections of divine covenant-gift cannot be recovered. This is not a statement about the security of those who are truly in Christ but about the finality of knowingly trading the covenant inheritance for the satisfactions of the moment.</p>',
    "18": '<p>A revelation of God: you have not come to a mountain that can be touched and that is burning with fire. The Sinai contrast sets up the superiority of the new covenant by describing what the community has NOT come to: the terrifying physical mountain, the darkness, storm, and blazing fire. The old covenant encounter with God was mediated through physical terror; the new covenant encounter is mediated through the Son in whom all that terror has been absorbed. The Sinai mountain repelled; the heavenly Mount Zion welcomes. The difference is the mediator.</p>',
    "19": '<p>A revelation of God: to the blast of a trumpet and to such a voice speaking words that those who heard it begged that no further word be spoken. The overwhelming character of the Sinai theophany — so terrifying that the people who experienced it begged for it to stop — reveals the unapproachable holiness of God under the old covenant. The new covenant does not remove this holiness but provides access to it through a mediator who has borne its full weight: Christ\'s death absorbed the consuming fire so that the community can draw near without being consumed by it.</p>',
    "20": '<p>A revelation of God: they could not bear what was commanded — "If even an animal touches the mountain, it shall be stoned." The absolute barrier between the ordinary and the divine at Sinai — enforced with death even for animals — is the shadow of what the new covenant removes. Under the old, even accidental contact with the holy mountain brought death. Under the new covenant, intentional drawing near is commanded (10:22) — because Christ has taken upon himself the death that contact would have required and has opened the way permanently and safely.</p>',
    "21": '<p>A revelation of God: the sight was so terrifying that Moses said, "I am trembling with fear." Even Moses — the mediator, the friend of God, the one to whom God spoke face to face — trembled at the Sinai manifestation. The mediator of the first covenant trembled; the community of the new covenant approaches without trembling, not because the holiness is less but because the Mediator of the new covenant endured rather than trembled at the cross. His endurance for them is the ground of their boldness; his session at the right hand is the proof that the terror has been absorbed.</p>',
    "22": '<p>A direct revelation: you have come to Mount Zion and to the city of the living God, the heavenly Jerusalem, and to innumerable angels in festal gathering. The community\'s present status — not future hope but present arrival — is described in terms of the heavenly assembly they have already joined through Christ\'s priestly ministry. The "you have come" (<em>proselelythate</em>, perfect tense) is the access already granted through Christ\'s entry into the heavenly sanctuary. The community worships not in a room but in the heavenly Jerusalem, alongside myriads of angels, in the festal assembly of the eschatological age that Christ has inaugurated.</p>',
    "23": '<p>A direct revelation: to the assembly of the firstborn whose names are written in heaven, and to God the Judge of all, and to the spirits of the righteous made perfect. The community approaches God the Judge not in terror but in the confidence that the Judge\'s verdict on them is already given in Christ. "The firstborn" whose names are registered in heaven are those who share the status of the one firstborn Son — adopted children of God through him (2:11-12). "The righteous made perfect" are the OT faithful (11:39-40) who have received what they were waiting for, together with the new covenant community, in the completed atonement of Christ.</p>',
    "24": '<p>A direct revelation: to Jesus, the mediator of a new covenant, and to the sprinkled blood that speaks a better word than the blood of Abel. The two comparisons of ch12 converge here: Sinai\'s mediator vs. the new covenant\'s mediator (Moses trembled; Jesus endured), and Abel\'s blood (crying for vengeance from the ground) vs. Jesus\'s blood (speaking forgiveness). The "better word" that Christ\'s blood speaks is the gospel itself: not "avenge me!" but "forgive them!" The blood of the new covenant mediator is the foundation of the community\'s access and the answer to all the cries for justice that have accumulated since the first murder.</p>',
    "25": '<p>A direct revelation: see to it that you do not refuse him who is speaking. The one who speaks is Christ — the Son through whom God has spoken in these last days (1:2). The comparison: those who refused the earthly voice (Moses at Sinai) could not escape; how much more inescapable will be the rejection of the one who speaks from heaven. To refuse Christ is to repeat the wilderness generation\'s refusal on an incomparably greater scale — not the voice of a human mediator but the voice of the Son himself, speaking through the Spirit and the word from the right hand of God.</p>',
    "26": '<p>A fulfillment: at that time his voice shook the earth, but now he has promised, "Once more I will shake not only the earth but also the heavens" (Hag 2:6). The Haggai 2:6 promise of the final cosmic shaking is applied to the Christ-event: the cross-resurrection-ascension is the eschatological shaking that dislodges the old order — the Levitical system, the Sinai covenant, the structures of the present age — to reveal the unshakeable kingdom. Haggai promised a greater Presence than the first temple had; that Presence is Christ, in whom the fullness of the Godhead dwells bodily (Col 2:9).</p>',
    "27": '<p>A direct revelation: the words "once more" indicate the removing of what can be shaken — created things — so that what cannot be shaken may remain. The distinction between the shakeable (the created order and its institutions) and the unshakeable (the kingdom of God in Christ) is the eschatological framework for the community\'s present situation. The suffering and opposition they experience are the shaking of the old order; what they are receiving — the kingdom of Christ — is already unshakeable because it is grounded in his completed work, his indestructible resurrection-life, and his permanent session at the right hand.</p>',
    "28": '<p>A fulfillment: we are receiving a kingdom that cannot be shaken — the fulfillment of Haggai\'s promised shaking. The once-more shaking of heaven and earth has been accomplished in the Christ-event, leaving the unshakeable kingdom as the permanent inheritance of those in Christ. The community that suffered the shaking of persecution receives instead the unshakeable kingdom — because they belong to the one whose resurrection is the first-fruits of the new unshakeable creation. Their worship is the community\'s participation in the kingdom that is already real even while it awaits its full manifestation.</p>',
    "29": '<p>A revelation of God: our God is a consuming fire (Deut 4:24). The character of God revealed at Sinai has not changed in the new covenant — he remains the consuming fire. The new covenant does not reduce God\'s holiness but provides access to it through the one who was consumed in the community\'s place: Christ bore the fire on the cross so that those who are in him are refined rather than consumed. The same consuming fire that threatens apostates (10:27) is the fire that purifies the faithful through discipline (vv. 10-11). Christ absorbed it; the community is shaped by it toward the holiness they will share.</p>'
  },
  "13": {
    "1": '<p>A revelation of God: let brotherly love continue. The <em>philadelphia</em> commanded of the community is the love appropriate to those who are brothers and sisters in Christ — adopted children of the same Father, fellow members of the same body. The love commanded is not generic human affection but the specific covenant-love that flows from their shared identity in Christ. The God who gave the Son for enemies (the supreme act of love) is the one whose character of love is to be reproduced in the community\'s life together.</p>',
    "2": '<p>A revelation of God: do not forget to show hospitality to strangers, for by doing so some have entertained angels without knowing it. The reference to Abraham\'s hospitality at Mamre (Gen 18:1-15) — when he received three visitors who were divine messengers — establishes the principle: the community\'s welcome of strangers may be a welcome of divine messengers. The God who has welcomed the community — once strangers and aliens — into his household through Christ (Eph 2:19) is the ground and pattern of the hospitality commanded.</p>',
    "3": '<p>A theme: remember those in prison as if you were their fellow prisoners, and those who are mistreated as if you yourselves were suffering. The solidarity with suffering members is the practical expression of body-life in Christ: because the community is one body in him, what one member suffers all members share. Christ himself identified with the imprisoned and suffering (Matt 25:35-36: "I was in prison and you came to me"), and the community that identifies with its suffering members identifies with him. The prison visits and solidarity are not merely charity but participation in the reproach of Christ.</p>',
    "4": '<p>A revelation of God: let marriage be held in honor by all and the marriage bed kept pure, for God will judge the sexually immoral and the adulterous. The sanctity of marriage reflects the covenant-faithfulness that characterizes God\'s relationship with his people — a theme running through the prophets (Hosea, Ezekiel) and recapitulated in Christ as the bridegroom of the church (Eph 5:25-32). The judgment on sexual immorality is the judicial faithfulness of the God who takes covenant-loyalty seriously in both the covenant of marriage and the covenant of redemption: unfaithfulness in the lesser covenant mirrors the unfaithfulness that apostasy represents in the greater.</p>',
    "5": '<p>A direct revelation: keep your life free from love of money, and be content with what you have, for he has said, "Never will I leave you; never will I forsake you" (Deut 31:6). The promise originally given to Israel entering the land is applied to the community as the ground of contentment. Their security is not in wealth or property (which can be confiscated, as 10:34 records) but in the presence of Christ who has promised never to abandon them. The one who has secured the eternal inheritance (9:15) is the one who promises never to leave — so no earthly resource is needed as security or supplement.</p>',
    "6": '<p>A direct revelation: so we say with confidence, "The Lord is my helper; I will not be afraid. What can anyone do to me?" (Ps 118:6-7). The community\'s fearlessness in the face of human threat is grounded in the conviction that Christ — the same yesterday, today, and forever (v. 8) — is their helper. What could be done to them is answered by what has already been done for them: the cross and resurrection met the worst that human hostility can bring, and the resurrection proved that human opposition cannot have the final word. The Psalm\'s confidence is the community\'s inheritance in Christ.</p>',
    "7": '<p>A direct revelation: remember your leaders who spoke the word of God to you; consider the outcome of their way of life, and imitate their faith. The leaders whose lives ended in faithful witness are the local embodiment of what the cloud of witnesses in ch. 11 represents: completed faith as the pattern for continuing faith. Their "outcome" (<em>ekbasis</em>) — how they ended, typically through endurance in the face of death — demonstrates that the faith they proclaimed was worth holding. Their example points to Christ, the pioneer and perfecter of faith who went before all of them and whose path they walked.</p>',
    "8": '<p>A direct revelation: Jesus Christ is the same yesterday and today and forever. The eternal constancy of Christ is the Christological ground for the community\'s theological stability: the same Christ who died (yesterday) is alive and interceding (today) and will return (forever). The false teachers\' novelties are ruled out not merely by tradition but by the unchangeableness of Christ himself — he does not update his gospel or revise his person. The community anchored to this eternal Christ is immune to the drift that religious fashion produces.</p>',
    "9": '<p>A direct revelation: do not be carried away by all kinds of strange teachings. It is good for the heart to be strengthened by grace, not by ceremonial foods. The strange teachings — likely food-regulations and ceremonial requirements of the Levitical system — are contrasted with the grace of God in Christ. The heart strengthened by grace — the free, unearned favor of God given through Christ\'s atonement — is stable and settled, not susceptible to the anxiety-driven ritual-keeping of those seeking to establish their own righteousness. Christ is the grace; his atonement is the stability the heart requires. Ceremonial foods offer the shadow; Christ is the substance.</p>',
    "10": '<p>A direct revelation: we have an altar from which those who minister at the tabernacle have no right to eat. The "altar" from which the community eats is Christ himself — his body and blood, the new covenant meal. The Levitical priests who serve at the tabernacle have no access to this altar because they remain within the shadow-system that Christ has superseded. The community\'s participation in Christ (the Lord\'s Supper as participation in his body and blood, 1 Cor 10:16) is the privilege that the entire Levitical apparatus — despite its elaborate priestly machinery — could not offer its own ministers.</p>',
    "11": '<p>A shadow: the bodies of those animals whose blood is brought into the Most Holy Place by the high priest as a sin offering are burned outside the camp. The sin-offering animals burned outside the camp are the OT shadow of Christ\'s suffering outside the city gate (v. 12). The animals whose blood entered the sanctuary on Yom Kippur were themselves consumed outside — not eaten by the priests, not within the sacred precincts, but in the place of exclusion. This spatial theology of exclusion-as-purification is the type that Christ enacts definitively: he goes outside, bears the exclusion and shame, and accomplishes the purification that the burned animals could only signify.</p>',
    "12": '<p>A direct revelation: Jesus also suffered outside the city gate to make the people holy through his own blood. The purposive suffering outside the gate is the revelation of the cross\'s nature: not accidental or merely judicial but the fulfillment of the spatial theology of the sin-offering — the sacrifice that bears sin is removed to the place of exclusion, outside the camp, outside the gate. To sanctify through his own blood is the full Christological claim: his blood is the means, the sanctification of the people is the goal, and his suffering in the place of exclusion is the historical event that accomplishes both for all who are in him.</p>',
    "13": '<p>A direct revelation: let us, then, go to him outside the camp, bearing the disgrace he bore. The community is called to follow Christ outside the camp — to leave the security of institutionalized religious legitimacy (the Temple system, the established centers of social and religious honor) and identify with the crucified, excluded, disgraced Messiah. The reproach of Christ (11:26; 10:33) is the community\'s calling: to bear with him the social and religious exclusion that his death-outside-the-gate represents. The way into the heavenly city runs through the gate of the earthly city\'s rejection.</p>',
    "14": '<p>A direct revelation: for here we do not have an enduring city, but we are looking for the city that is to come. The eschatological city — the new Jerusalem, the city with foundations that Abraham sought (11:10) — is the community\'s permanent orientation. The present city (Jerusalem, Rome, any earthly center of power or prestige) is not the enduring city. Christ has entered the heavenly city by his ascension (4:14; 9:24) and has secured the community\'s citizenship in it. The community lives in the present city as pilgrims and strangers, looking toward the one Christ has entered and prepared for them to inhabit at the resurrection.</p>',
    "15": '<p>A direct revelation: through Jesus, let us continually offer to God a sacrifice of praise — the fruit of lips that openly profess his name. The sacrifice of praise offered through Jesus is the new covenant\'s replacement of the Levitical sacrificial system. The community\'s worship — verbal, perpetual, through the mediation of Christ — is itself a priestly act: they are a royal priesthood (1 Pet 2:9) offering through the great high priest. The "fruit of lips" echoes Hosea 14:2, where return to God involves verbal confession rather than bulls. Christ is the altar through which this offering becomes acceptable; without him, no praise reaches the Father.</p>',
    "16": '<p>A revelation of God: do not forget to do good and to share with others, for with such sacrifices God is pleased. The doing of good and sharing are called "sacrifices with which God is pleased" — the ethical life of the community is priestly service. What pleases God is not ritual repetition (the Levitical system exhausted) but the overflow of the atonement\'s work: love, generosity, practical solidarity with those in need. The God who was not pleased by burnt offerings (10:6) is pleased by the love that the Spirit produces in those who have been sanctified by Christ\'s one offering and who now live in the grace of the new covenant.</p>',
    "17": '<p>A revelation of God: have confidence in your leaders and submit to their authority, for they keep watch over your souls as those who will give an account. The leaders who give an account to God are exercising a delegated form of the shepherding role that Christ exercises as the great Shepherd (v. 20). The community\'s submission to godly leadership is its submission to the Shepherd\'s care through human instruments. The leaders who watch over souls (<em>psychas</em>) are accountable to the one who gave his soul (<em>psychēn</em>) for the sheep (John 10:11) — all pastoral responsibility is grounded in and answerable to the supreme Shepherd who laid down his life.</p>',
    "18": '<p>A revelation of God: pray for us — we are sure that we have a clear conscience and desire to live honorably in every way. The author\'s clear conscience is not self-congratulation but the testimony of a life lived in the light of the atonement — the conscience cleansed by the blood of Christ (9:14; 10:22). The request for prayer is the practical acknowledgment that the community\'s life together, including the leaders\' ministry, is sustained by intercession — the same kind of intercession that Christ himself exercises from the right hand of God (7:25) on behalf of all who draw near through him.</p>',
    "19": '<p>A theme: I particularly urge you to pray so that I may be restored to you soon. The apostolic desire for restoration to the community reflects the relational structure of the new covenant people: not anonymous worshippers before an impersonal deity but a people bound together in love, mutual responsibility, and pastoral relationship. The mutual prayer requested — community for leader, leader for community — is the horizontal expression of the vertical intercession that Christ maintains for all his people, and in which the community participates by praying for one another.</p>',
    "20": '<p>A direct revelation: now may the God of peace, who through the blood of the eternal covenant brought back from the dead our Lord Jesus, that great shepherd of the sheep — the closing benediction is a Christological compendium. God of peace: the covenant relationship restored by the atonement. Brought back from the dead: the resurrection as God\'s own act, vindicating the Son. Our Lord Jesus: the human name and divine title of the mediator. The great shepherd: the Ezekielian Davidic shepherd (Ezek 34:23) who gathers and leads God\'s flock. Blood of the eternal covenant: the atoning self-offering that inaugurates the covenant that will never be superseded. All that Hebrews has argued converges in this single ascription.</p>',
    "21": '<p>A direct revelation: may he equip you with everything good for doing his will, working in us what is pleasing in his sight, through Jesus Christ, to whom be glory forever and ever. The closing prayer applies the entire Christological argument to the practical ethical life of the community. The equipping for good works, the doing of God\'s will, and the production of what pleases God are all "through Jesus Christ" — his high-priestly mediation grounds not only the community\'s access to God but their ongoing moral formation. The doxology to Christ (to whom be glory forever) is the fitting conclusion: the letter\'s sustained argument for his supremacy and finality ends with worship directed to him.</p>',
    "22": '<p>A revelation of God: brothers and sisters, I urge you to bear with my word of exhortation, for in fact I have written to you quite briefly. The author characterizes Hebrews as a "word of exhortation" — the pastoral genre of urgent encouragement. All the sustained argument for Christ\'s supremacy has been in service of this exhortation: hold fast to him, draw near through him, endure for him. The brevity comment is honest: relative to its subject — the pioneer and perfecter, the great high priest, the mediator of the new covenant — every treatment is brief. The letter opens what cannot be closed; it introduces the one who cannot be exhausted.</p>',
    "23": '<p>A revelation of God: I want you to know that our brother Timothy has been released. If he arrives soon, I will come with him to see you. The personal note about Timothy places the letter in the community of apostolic ministry — the network through which the gospel has been carried and will continue to be carried. The community of Christ is the community of those who share in this gospel-carrying: bound to one another not by geography or ethnicity but by their common Lord and their common commission to speak and embody the word of exhortation to the world.</p>',
    "24": '<p>A revelation of God: greet all your leaders and all the Lord\'s people. Those from Italy send you their greetings. The greetings from "those from Italy" — believers sending greetings across distance — signal the catholicity of the community: those in one location are bound to those in another, not by physical proximity but by their common Lord. The community of Christ transcends ethnic, geographic, and social boundaries because it is defined by its relationship to the one Mediator of the new covenant, who has made of many one new humanity (Eph 2:15).</p>',
    "25": '<p>A direct revelation: grace be with you all. The closing grace-benediction is Christological in content: the grace is specifically the grace of the Lord Jesus Christ — the free, unearned favor of God given through the atonement. All that Hebrews has argued — the Son\'s supremacy, the high priesthood, the once-for-all sacrifice, the new covenant, the opened sanctuary, the unshakeable kingdom — is summarized in the single word "grace." The community lives in the field of this grace, which is nothing other than the person and work of Jesus Christ given freely to those who draw near through him.</p>'
  }
}

def main():
    existing = load_comm('mkt-christ', 'hebrews')
    merge_comm(existing, HEBREWS)
    save_comm('mkt-christ', 'hebrews', existing)
    total = sum(len(v) for v in existing.values())
    print(f'Hebrews mkt-christ: {len(existing)} chapters, {total} verses written.')

if __name__ == '__main__':
    main()
